import android.content.Context;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;

public class BankingActivity extends AppCompatActivity {

    private double accountBalance = 1000.00; // Initial balance
    private EditText transactionAmountInput;
    private TextView balanceDisplay;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);

        transactionAmountInput = findViewById(R.id.transactionAmountInput);
        balanceDisplay = findViewById(R.id.balanceDisplay);
        Button depositButton = findViewById(R.id.depositButton);
        Button withdrawButton = findViewById(R.id.withdrawButton);

        updateBalanceDisplay();

        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransaction(true);
            }
        });

        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransaction(false);
            }
        });
    }

    private void processTransaction(boolean isDeposit) {
        String input = transactionAmountInput.getText().toString();
        if (input.isEmpty()) {
            Toast.makeText(this, "Please enter an amount", Toast.LENGTH_SHORT).show();
            return;
        }

        double amount = Double.parseDouble(input);
        if (isDeposit) {
            accountBalance += amount;
            Toast.makeText(this, "Deposited: " + amount, Toast.LENGTH_SHORT).show();
        } else {
            if (amount > accountBalance) {
                Toast.makeText(this, "Insufficient funds", Toast.LENGTH_SHORT).show();
                return;
            }
            accountBalance -= amount;
            Toast.makeText(this, "Withdrawn: " + amount, Toast.LENGTH_SHORT).show();
        }
        updateBalanceDisplay();
    }

    private void updateBalanceDisplay() {
        balanceDisplay.setText("Balance: $" + String.format("%.2f", accountBalance));
    }
}